  object QueryValidator {
    private val DangerousPatterns = Seq(
      "(?i)\\binsert\\b",
      "(?i)\\bupdate\\b",
      "(?i)\\bdelete\\b",
      "(?i)\\bmerge\\b",
      "(?i)\\bdrop\\b",
      "(?i)\\btruncate\\b",
      "(?i)\\balter\\b",
      "(?i)\\bcreate\\b",
      "(?i)\\breplace\\b",
      "(?i)\\bgrant\\b",
      "(?i)\\brevoke\\b",
      "(?i)\\bset\\b",
      "(?i)\\buse\\b",
