      "(?i)\\brefresh\\b",
      "(?i)\\bcache\\b",
      "(?i)\\buncache\\b",
      "(?i)\\bcheckpoint\\b"
    )

    def validate(sql: String): Either[String, String] = {
      if (sql == null || sql.trim.isEmpty) Left("SQL query must not be empty")
      else if (sql.contains(";")) Left("Multiple statements are not allowed")
      else if (DangerousPatterns.exists(_.r.findFirstIn(sql).nonEmpty)) Left("Only read-only SELECT queries are allowed")
      else if (!sql.trim.toLowerCase.startsWith("select") && !sql.trim.toLowerCase.startsWith("with"))
        Left("Query must start with SELECT or WITH")
      else Right(sql.trim)
