    private def dataframeToMaps(df: DataFrame): Seq[Map[String, String]] = {
      val rows = df.collect()
      val cols = df.columns
      rows.map { row =>
        cols.zipWithIndex.map { case (colName, idx) =>
          val value = Option(row.get(idx)).map(_.toString).getOrElse("null")
          colName -> value
        }.toMap
      }.toSeq
    }
  }

